import{_ as e,o as a,c as i,aB as r}from"./chunks/framework.BTFJqP47.js";const g=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md","lastUpdated":null}'),n={name:"benchmarks.md"};function s(l,t,h,o,c,d){return a(),i("div",null,[...t[0]||(t[0]=[r(`<h1 id="Benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#Benchmarks" aria-label="Permalink to &quot;Benchmarks {#Benchmarks}&quot;">​</a></h1><p>This page documents performance comparisons between EpiBranch.jl and equivalent R packages. The benchmark scripts are in <a href="https://github.com/epiforecasts/EpiBranch.jl/tree/main/benchmarks" target="_blank" rel="noreferrer"><code>benchmarks/</code></a> and can be run locally to reproduce results on your own hardware.</p><p>These are indicative timings, not rigorous benchmarks. Both the R and Julia implementations are under active development, so numbers will change over time.</p><h2 id="How-to-run" tabindex="-1">How to run <a class="header-anchor" href="#How-to-run" aria-label="Permalink to &quot;How to run {#How-to-run}&quot;">​</a></h2><p>Julia benchmarks (requires BenchmarkTools and StableRNGs in your default environment):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/benchmark_julia.jl</span></span></code></pre></div><p>R benchmarks (requires <a href="https://github.com/epiverse-trace/epichains" target="_blank" rel="noreferrer">epichains</a> and <a href="https://github.com/epiforecasts/ringbp" target="_blank" rel="noreferrer">ringbp</a>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Rscript</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/benchmark_r.R</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Rscript</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/benchmark_r_ringbp.R</span></span></code></pre></div><h2 id="Chain-simulation-vs-epichains" tabindex="-1">Chain simulation (vs epichains) <a class="header-anchor" href="#Chain-simulation-vs-epichains" aria-label="Permalink to &quot;Chain simulation (vs epichains) {#Chain-simulation-vs-epichains}&quot;">​</a></h2><p>Simulating 1000 transmission chains to completion, comparing EpiBranch.jl with R&#39;s <a href="https://github.com/epiverse-trace/epichains" target="_blank" rel="noreferrer">epichains</a> package.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Scenario</th><th style="text-align:right;">R (epichains)</th><th style="text-align:right;">Julia (EpiBranch)</th></tr></thead><tbody><tr><td style="text-align:right;">1000 chains, Poisson(0.9)</td><td style="text-align:right;">22.5 ms</td><td style="text-align:right;">1.6 ms</td></tr><tr><td style="text-align:right;">1000 chains, NegBin(0.8, 0.5)</td><td style="text-align:right;">12.6 ms</td><td style="text-align:right;">1.0 ms</td></tr><tr><td style="text-align:right;">1000 chains + generation time</td><td style="text-align:right;">31.0 ms</td><td style="text-align:right;">1.9 ms</td></tr><tr><td style="text-align:right;">Chain statistics</td><td style="text-align:right;">0.48 ms</td><td style="text-align:right;">0.27 ms</td></tr><tr><td style="text-align:right;">Analytical log-likelihood</td><td style="text-align:right;">0.15 ms</td><td style="text-align:right;">&lt; 0.001 ms</td></tr></tbody></table><h2 id="Intervention-scenarios-vs-ringbp" tabindex="-1">Intervention scenarios (vs ringbp) <a class="header-anchor" href="#Intervention-scenarios-vs-ringbp" aria-label="Permalink to &quot;Intervention scenarios (vs ringbp) {#Intervention-scenarios-vs-ringbp}&quot;">​</a></h2><p>Simulating 500 outbreaks with NegBin(2.5, 0.16) offspring, isolation, and contact tracing, capped at 5000 cases. Comparing EpiBranch.jl with R&#39;s <a href="https://github.com/epiforecasts/ringbp" target="_blank" rel="noreferrer">ringbp</a> package.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Scenario</th><th style="text-align:right;">R (ringbp)</th><th style="text-align:right;">Julia (EpiBranch)</th></tr></thead><tbody><tr><td style="text-align:right;">No interventions</td><td style="text-align:right;">9,893 ms</td><td style="text-align:right;">707 ms</td></tr><tr><td style="text-align:right;">50% contact tracing</td><td style="text-align:right;">10,374 ms</td><td style="text-align:right;">707 ms</td></tr><tr><td style="text-align:right;">50% tracing + quarantine</td><td style="text-align:right;">9,319 ms</td><td style="text-align:right;">707 ms</td></tr></tbody></table><p>The Julia column uses the same scenario (isolation + 50% contact tracing, scenario 7 in <code>benchmark_julia.jl</code>). The ringbp scenarios differ slightly in parameterisation (incubation-linked generation time, presymptomatic transmission fraction), so these are order-of-magnitude comparisons rather than like-for-like.</p><h2 id="Other-benchmarks" tabindex="-1">Other benchmarks <a class="header-anchor" href="#Other-benchmarks" aria-label="Permalink to &quot;Other benchmarks {#Other-benchmarks}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Scenario</th><th style="text-align:right;">Julia (EpiBranch)</th></tr></thead><tbody><tr><td style="text-align:right;">Line list generation (200 cases)</td><td style="text-align:right;">0.008 ms</td></tr><tr><td style="text-align:right;">NegBin fit from 1000 offspring counts</td><td style="text-align:right;">0.71 ms</td></tr></tbody></table><p>No direct R comparison is included for line list generation (simulist requires epiparameter database setup) or offspring fitting.</p><h2 id="Notes" tabindex="-1">Notes <a class="header-anchor" href="#Notes" aria-label="Permalink to &quot;Notes {#Notes}&quot;">​</a></h2><ul><li><p>Julia timings exclude compilation (measured after warm-up using <a href="https://github.com/JuliaCI/BenchmarkTools.jl" target="_blank" rel="noreferrer">BenchmarkTools.jl</a>)</p></li><li><p>R timings use <a href="https://cran.r-project.org/package=microbenchmark" target="_blank" rel="noreferrer">microbenchmark</a></p></li><li><p>All timings are medians from multiple runs</p></li><li><p>Hardware differences will affect absolute numbers; ratios are more informative</p></li><li><p>Neither implementation is specifically optimised for speed</p></li><li><p>Last run: April 2026</p></li></ul>`,20)])])}const m=e(n,[["render",s]]);export{g as __pageData,m as default};
